from beeai import AgentRunner
from vex_sdk import VexDetector

class TenantLeakDetector(VexDetector):
    def on_tool_call(self, event):
        tool_tenant = event.get('args', {}).get('tenant_id')
        session_tenant = event.session.context.get('tenant_id')
        if tool_tenant != session_tenant:
            self.flag_violation(
                'TENANT_LEAK',
                f'Tool called with tenant {tool_tenant} but session is {session_tenant}',
                event
            )

