class AuthMiddleware:
    def __init__(self, verifier):
        self.verifier = verifier

    def require_auth(self, fn):
        @wraps(fn)
        def wrapped(event):
            context = event.session.context
            if not self.verifier.validate_tenant(context.get('tenant_id'), context.get('user_id')):
                raise PermissionError('Unauthorized tenant access')
