from beeai import ToolRegistry

class SecureToolRegistry(ToolRegistry):
    REQUIRED_SCOPES = {'tenant_id', 'user_id'}

    def register_secure_tool(self, name, fn, required_scopes=None):
        if required_scopes is None:
            required_scopes = self.REQUIRED_SCOPES

        @wraps(fn)
        def secure_tool_call(args):
            # Auto-inject session context
            args['tenant_id'] = args.get('tenant_id', self.current_session.context['tenant_id'])
            args['user_id'] = args.get('user_id', self.current_session.context['user_id'])

            # Validate scopes
            missing = required_scopes - set(args.keys())
            if missing:
                raise ValueError(f'Missing auth scopes: {missing}')
            return fn(args)

        self.register_tool(name, secure_tool_call)

from cryptography.fernet import Fernet
import json
from beeai import MemoryStore

class SecureMemoryStore(MemoryStore):
    def __init__(self):
        self.tenant_keys = {}

    def _get_tenant_key(self, tenant_id):
        if tenant_id not in self.tenant_keys:
            self.tenant_keys[tenant_id] = Fernet.generate_key()
        return self.tenant_keys[tenant_id]

    def save(self, session_id, state):
        tenant_id = state['context']['tenant_id']
        fernet = Fernet(self._get_tenant_key(tenant_id))
        encrypted = fernet.encrypt(json.dumps(state).encode())
        super().save(session_id, encrypted)

    def load(self, session_id):
        raw = super().load(session_id)
        # Decrypt only with matching tenant session context
        tenant_id = self.current_session.context['tenant_id']
        fernet = Fernet(self._get_tenant_key(tenant_id))
        return json.loads(fernet.decrypt(raw).decode())

