from vex_sdk import VexAgent
from beeai import AgentRunner

# Install: pip install beeai-framework vex-sdk

vex = VexAgent(api_key="your-vex-key")

# Auto-register all BeeAI auth detectors
@vex.register_detector('beeai-auth')
def beeai_auth_guard(agent_event):
    if agent_event.type == 'tool_call':
        # Enforce tenant isolation
        tool_tenant = agent_event.args.get('tenant_id')
        if tool_tenant != agent_event.session.context.get('tenant_id'):
            return vex.block('TENANT_LEAK', auto_fix=True)

    if agent_event.type == 'memory_load':
        # Validate JWT expiration
        auth_state = agent_event.state.get('auth')
        if auth_state and 'exp' in auth_state:
            if auth_state['exp'] < time.time():
                return vex.block('EXPIRED_TOKEN', auto_remediate=True)

# Zero-config integration
agent_runner = AgentRunner()
agent_runner.add_event_listener(vex.listener())

print('✅ Vex BeeAI Auth Guard active - all violations auto-remediated')
